const CDN = "https://cdn.cloudflare.steamstatic.com/apps/dota2/images/dota_react/heroes/icons";

/** Official square icon URL for a hero id, or undefined if unknown. */
export function heroIconUrl(heroId: string): string | undefined {
  const name = HERO_ICON_NAME[heroId];
  return name ? `${CDN}/${name}.png` : undefined;
}
